SELECT number_of_members
FROM churches
WHERE church_name = 'First United Methodist Church of Peoria';

SELECT COUNT(*) AS total_chart_views
FROM chart_views
WHERE user_id = 0;

SELECT COUNT(*) AS ordained_count
FROM clergy_members
WHERE strftime('%Y', ordination_date) = '2005';

SELECT COUNT(*) AS valid_gcno_count
FROM GCNO
WHERE expiry_date > CURRENT_DATE;

SELECT clergy_name
FROM clergy_members
WHERE ordination_date >= '2001-01-01';

SELECT clergy_name
FROM clergy_members
WHERE clergy_id = 1;

SELECT number_of_members
FROM churches
WHERE church_id = 1;

SELECT MAX(duration)
FROM chart_views
WHERE user_id = 0;

SELECT AVG(duration) AS average_view_duration
FROM chart_views
WHERE chart_type = 'Pie Chart' AND chart_name = 'Church Members';

SELECT user_id, chart_name
FROM chart_views
WHERE duration > 10;

SELECT clergy_name
FROM clergy_members
ORDER BY clergy_name;

SELECT SUM(number_of_members) AS total_members
FROM churches
WHERE district_id = 1;

SELECT church_name, number_of_members
FROM churches
ORDER BY number_of_members DESC;
